// ===================================================
// WF-ERROR Step 1: 에러 정보 파싱
// n8n Error Trigger가 전달하는 실행 에러 데이터를 구조화
// KST 시간대로 변환하여 텔레그램 메시지 가독성 확보
// ===================================================

const input = $input.first().json;

// === 에러 정보 추출 (n8n Error Trigger 구조) ===
const execution = input.execution || {};
const workflow = input.workflow || {};

const workflowName = workflow.name || '(알 수 없음)';
const workflowId = String(workflow.id || '');
const executionId = String(execution.id || '');
const lastNodeExecuted = execution.lastNodeExecuted || '(알 수 없음)';
const executionMode = execution.mode || 'unknown';

// === 에러 메시지 추출 ===
// n8n은 여러 구조로 에러 데이터를 전달할 수 있음
let errorMessage = '(에러 메시지 없음)';
if (input.execution && input.execution.error) {
  errorMessage = input.execution.error.message || JSON.stringify(input.execution.error);
} else if (input.error) {
  errorMessage = input.error.message || JSON.stringify(input.error);
}

// 에러 메시지 길이 제한 (텔레그램 4096자 제한 대비)
if (errorMessage.length > 500) {
  errorMessage = errorMessage.substring(0, 500) + '...(생략)';
}

// === KST 시간 변환 ===
const now = new Date();
const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
const pad = (n) => String(n).padStart(2, '0');
const timestampKST = kst.getFullYear() + '-'
  + pad(kst.getMonth() + 1) + '-'
  + pad(kst.getDate()) + ' '
  + pad(kst.getHours()) + ':'
  + pad(kst.getMinutes()) + ':'
  + pad(kst.getSeconds());

// === 텔레그램 메시지 구성 ===
// Markdown 특수문자 이스케이프 (_, *, `, [, ])
function escapeMd(str) {
  if (!str) return '';
  return String(str)
    .replace(/\\/g, '\\\\')
    .replace(/_/g, '\\_')
    .replace(/\*/g, '\\*')
    .replace(/`/g, '\\`')
    .replace(/\[/g, '\\[')
    .replace(/\]/g, '\\]');
}

const telegramMessage = '\u26A0\uFE0F *n8n \uC5D0\uB7EC*\n\n'
  + '\uC6CC\uD06C\uD50C\uB85C\uC6B0: ' + escapeMd(workflowName) + '\n'
  + '\uB178\uB4DC: ' + escapeMd(lastNodeExecuted) + '\n'
  + '\uC5D0\uB7EC: ' + escapeMd(errorMessage) + '\n'
  + '\uC2E4\uD589ID: `' + executionId + '`\n'
  + '\uBAA8\uB4DC: ' + executionMode + '\n'
  + '\uC2DC\uAC01: ' + timestampKST + ' (KST)';

// === NocoDB 로그용 데이터 ===
const logContent = JSON.stringify({
  workflowName: workflowName,
  workflowId: workflowId,
  nodeName: lastNodeExecuted,
  errorMessage: errorMessage,
  executionId: executionId,
  executionMode: executionMode
});

return [{
  json: {
    _telegramMessage: telegramMessage,
    _logContent: logContent,
    _timestampISO: now.toISOString(),
    _workflowName: workflowName,
    _executionId: executionId
  }
}];
